#include<bits/stdc++.h>
using namespace std;
set<int> vis[100010],ans[100010];
int a[100010],b[100010];
int find(int x)
{
	return x==a[x]?x:a[x]=find(a[x]);
}
int main()
{
	int n,k,x,y;
	scanf("%d%d",&n,&k);
	for(int i=1;i<=n;i++)
	{
		a[i]=i;
		b[i]=i;
		vis[i].insert(i);
	}
	for(int i=1;i<=k;i++)
	{
		scanf("%d%d",&x,&y);
		swap(b[x],b[y]);
		vis[b[x]].insert(y);
		vis[b[y]].insert(x);
	}
	for(int i=1;i<=n;i++)
	{
		x=find(i);
		y=find(b[i]);
		if(x!=y)
		{
			a[y]=x;
		}
	}
	for(int i=1;i<=n;i++)
	{
		x=find(i);
		vis[x].insert(vis[i].begin(),vis[i].end());
	}
	for(int i=1;i<=n;i++)
	{
		printf("%d\n",vis[find(i)].size());
	}
	return 0;
}
